import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { 
  Diamond, Search, Calendar, Users, MapPin, Star, 
  LogOut, Home, BookOpen, Heart, User, Filter,
  ChevronRight, Check, ChevronDown, X
} from 'lucide-react';

// HOTELS DATA
const HOTELS_DATA = [
  {
    id: 1,
    name: "Azure Palace",
    location: "Maldives",
    price: 2450,
    rating: 4.9,
    image: "https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800&q=80",
    amenities: ["Ocean View", "Private Pool", "SPA"],
    description: "Experience ultimate luxury in overwater villas with breathtaking ocean views.",
    maxGuests: 4,
    roomTypes: ["Overwater Villa", "Beach Suite", "Royal Pavilion"]
  },
  {
    id: 2,
    name: "Nebula Resort",
    location: "Dubai, UAE",
    price: 3200,
    rating: 5.0,
    image: "https://images.unsplash.com/photo-1582719508461-905c673771fd?w=800&q=80",
    amenities: ["City View", "SPA", "Butler Service"],
    description: "Futuristic luxury in the heart of Dubai with panoramic city views.",
    maxGuests: 3,
    roomTypes: ["Sky Suite", "Panoramic Room", "Executive Floor"]
  },
  {
    id: 3,
    name: "Crystal Bay",
    location: "Bora Bora",
    price: 4100,
    rating: 4.9,
    image: "https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80",
    amenities: ["Overwater", "Private Butler", "Helipad"],
    description: "Exclusive overwater bungalows with private butler service.",
    maxGuests: 2,
    roomTypes: ["Overwater Bungalow", "Beach Villa"]
  },
  {
    id: 4,
    name: "Skyline Penthouse",
    location: "New York, USA",
    price: 1800,
    rating: 4.8,
    image: "https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800&q=80",
    amenities: ["City View", "Rooftop Pool", "Gym"],
    description: "Luxury penthouse with stunning Manhattan skyline views.",
    maxGuests: 6,
    roomTypes: ["Penthouse Suite", "Executive Room", "City View Studio"]
  },
  {
    id: 5,
    name: "Mountain Retreat",
    location: "Swiss Alps",
    price: 2800,
    rating: 4.9,
    image: "https://images.unsplash.com/photo-1587061949409-02df41d5e562?w=800&q=80",
    amenities: ["Mountain View", "Fireplace", "Ski Access"],
    description: "Cozy luxury chalet with direct ski-in/ski-out access.",
    maxGuests: 8,
    roomTypes: ["Chalet Suite", "Alpine Room", "Ski Lodge"]
  },
  {
    id: 6,
    name: "Ocean Breeze",
    location: "Bali, Indonesia",
    price: 1200,
    rating: 4.7,
    image: "https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800&q=80",
    amenities: ["Beachfront", "Infinity Pool", "Yoga"],
    description: "Serene beachfront resort with world-class wellness facilities.",
    maxGuests: 4,
    roomTypes: ["Garden Villa", "Pool Suite", "Ocean Room"]
  }
];

// FIXED: Date Picker with forced visible dates using inline styles
const CustomDatePicker = ({ label, value, onChange, min, icon: Icon }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const pickerRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (pickerRef.current && !pickerRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [isOpen]);

  const getDaysInMonth = (year, month) => {
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay.getDate();
    const startingDay = firstDay.getDay();
    
    const days = [];
    for (let i = 0; i < startingDay; i++) {
      days.push(null);
    }
    for (let i = 1; i <= daysInMonth; i++) {
      days.push(i);
    }
    return days;
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
  };

  const isDateDisabled = (day) => {
    if (!day) return false;
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    const minDate = min ? new Date(min) : new Date();
    minDate.setHours(0, 0, 0, 0);
    return date < minDate;
  };

  const isSelected = (day) => {
    if (!day || !value) return false;
    const selected = new Date(value);
    return selected.getDate() === day && 
           selected.getMonth() === currentMonth.getMonth() && 
           selected.getFullYear() === currentMonth.getFullYear();
  };

  const selectDate = (day) => {
    if (!day || isDateDisabled(day)) return;
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    onChange(date.toISOString().split('T')[0]);
    setIsOpen(false);
  };

  const prevMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1));
  };

  const nextMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1));
  };

  const monthNames = ["January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"];

  const year = currentMonth.getFullYear();
  const month = currentMonth.getMonth();
  const days = getDaysInMonth(year, month);

  // FIXED: Force white color with inline styles as backup
  const dayButtonStyle = (disabled, selected) => ({
    color: selected ? '#ffffff' : (disabled ? '#4b5563' : '#ffffff'),
    backgroundColor: selected ? '#06b6d4' : (disabled ? 'transparent' : 'rgba(30, 41, 59, 0.8)'),
  });

  return (
    <div className="relative" ref={pickerRef}>
      <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1 ml-1">{label}</label>
      <div className="relative">
        <Icon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-cyan-400 pointer-events-none" />
        <button
          type="button"
          onClick={() => setIsOpen(!isOpen)}
          className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl focus:border-cyan-500/50 focus:outline-none text-white text-left hover:bg-slate-800/50 transition-colors"
        >
          {value ? formatDate(value) : 'Select date'}
        </button>
      </div>

      {/* FIXED: Calendar with explicit styling to ensure visibility */}
     {isOpen && (
  <div
    style={{
      position: 'fixed',
      top: '50%',
      left: '50%',
      transform: 'translate(-50%, -50%)',
      backgroundColor: '#0f172a',
      border: '1px solid rgba(255,255,255,0.1)',
      borderRadius: '16px',
      padding: '16px',
      minWidth: '320px',
      zIndex: 999999,
      boxShadow: '0 20px 60px rgba(0,0,0,0.6)'
    }}
  >
          {/* Month Header */}
          <div className="flex justify-between items-center mb-4 px-2">
            <button 
              onClick={prevMonth} 
              className="p-2 rounded-lg transition-colors hover:bg-white/10"
              style={{ color: '#ffffff' }}
              type="button"
            >
              <ChevronRight className="w-5 h-5 rotate-180" />
            </button>
            <span 
              className="font-semibold text-lg"
              style={{ color: '#ffffff' }}
            >
              {monthNames[month]} {year}
            </span>
            <button 
              onClick={nextMonth} 
              className="p-2 rounded-lg transition-colors hover:bg-white/10"
              style={{ color: '#ffffff' }}
              type="button"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>

          {/* Days Header */}
          <div className="grid grid-cols-7 gap-0 mb-2">
            {['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'].map((day, idx) => (
              <div 
                key={idx} 
                className="text-center text-xs py-2 font-medium"
                style={{ color: '#9ca3af' }}
              >
                {day}
              </div>
            ))}
          </div>

          {/* Calendar Grid - FIXED: Explicit inline styles for visibility */}
          <div className="grid grid-cols-7 gap-1">
            {days.map((day, idx) => {
              const disabled = isDateDisabled(day);
              const selected = isSelected(day);
              
              if (!day) {
                return <div key={idx} className="h-10" />;
              }
              
              return (
                <button
                  key={idx}
                  onClick={() => selectDate(day)}
                  disabled={disabled}
                  type="button"
                  className="h-10 w-full flex items-center justify-center text-sm rounded-lg transition-all font-medium border-0"
                  style={dayButtonStyle(disabled, selected)}
                >
                  {day}
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

const Dashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('browse');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedGuests, setSelectedGuests] = useState(2);
  const [checkIn, setCheckIn] = useState('');
  const [checkOut, setCheckOut] = useState('');
  const [showGuestDropdown, setShowGuestDropdown] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState(null);
  const [bookingSuccess, setBookingSuccess] = useState(false);
  const [hoveredHotel, setHoveredHotel] = useState(null);

  const guestOptions = [2, 3, 4, 5, 6, 7, 8];

  // Check if booking is allowed (both dates required)
  const canBook = checkIn && checkOut;

  const filteredHotels = useMemo(() => {
    let hotels = HOTELS_DATA;
    
    if (searchQuery.trim()) {
      hotels = hotels.filter(hotel => 
        hotel.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        hotel.location.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    
    hotels = hotels.filter(hotel => hotel.maxGuests >= selectedGuests);
    
    return hotels;
  }, [searchQuery, selectedGuests]);

  const handleSearchChange = useCallback((e) => {
    setSearchQuery(e.target.value);
  }, []);

  const handleCheckInChange = useCallback((value) => {
    setCheckIn(value);
    if (checkOut && new Date(checkOut) <= new Date(value)) {
      setCheckOut('');
    }
  }, [checkOut]);

  const handleCheckOutChange = useCallback((value) => {
    setCheckOut(value);
  }, []);

  const handleGuestSelect = useCallback((num) => {
    setSelectedGuests(num);
    setShowGuestDropdown(false);
  }, []);

  const toggleGuestDropdown = useCallback(() => {
    setShowGuestDropdown(prev => !prev);
  }, []);

  const handleBookNow = useCallback((hotel) => {
    // Only allow booking if dates are selected
    if (!checkIn || !checkOut) {
      alert('Please select check-in and check-out dates first');
      return;
    }
    setSelectedHotel(hotel);
  }, [checkIn, checkOut]);

  const confirmBooking = useCallback(() => {
    setBookingSuccess(true);
    setTimeout(() => {
      setBookingSuccess(false);
      setSelectedHotel(null);
      setActiveTab('bookings');
    }, 2000);
  }, []);

  const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const Sidebar = () => (
    <div className="w-64 bg-slate-900/50 border-r border-white/10 p-6 flex flex-col h-full">
      <div className="flex items-center gap-2 mb-8 cursor-pointer" onClick={() => setActiveTab('browse')}>
        <Diamond className="w-8 h-8 text-cyan-400" />
        <span className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">AI'STAY</span>
      </div>

      <nav className="space-y-2 flex-1">
        <SidebarItem 
          icon={Home} 
          label="Browse Hotels" 
          active={activeTab === 'browse'}
          onClick={() => setActiveTab('browse')}
        />
        <SidebarItem 
          icon={BookOpen} 
          label="My Bookings" 
          active={activeTab === 'bookings'}
          onClick={() => setActiveTab('bookings')}
        />
        <SidebarItem 
          icon={Heart} 
          label="Favorites" 
          active={activeTab === 'favorites'}
          onClick={() => setActiveTab('favorites')}
        />
        <SidebarItem 
          icon={User} 
          label="Profile" 
          active={activeTab === 'profile'}
          onClick={() => setActiveTab('profile')}
        />
      </nav>

      <div className="pt-6 border-t border-white/10">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-cyan-500 to-purple-500 flex items-center justify-center font-bold">
            {user?.name?.charAt(0) || 'U'}
          </div>
          <div>
            <p className="font-medium text-sm">{user?.name || 'User'}</p>
            <p className="text-xs text-gray-400">{user?.email || 'user@example.com'}</p>
          </div>
        </div>
        <button 
          onClick={onLogout}
          className="flex items-center gap-2 text-red-400 hover:text-red-300 transition-colors text-sm"
        >
          <LogOut className="w-4 h-4" /> Sign Out
        </button>
      </div>
    </div>
  );

  const SidebarItem = ({ icon: Icon, label, active, onClick }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 ${
        active 
          ? 'bg-gradient-to-r from-cyan-500/20 to-purple-500/20 border border-cyan-500/30 text-cyan-400' 
          : 'text-gray-400 hover:bg-white/5 hover:text-white'
      }`}
    >
      <Icon className="w-5 h-5" />
      <span className="font-medium">{label}</span>
    </button>
  );

  const MyBookings = () => (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold">My Bookings</h2>
      <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-8 text-center border border-white/10">
        <BookOpen className="w-16 h-16 text-gray-600 mx-auto mb-4" />
        <p className="text-gray-400">No bookings yet. Start exploring hotels!</p>
        <button 
          onClick={() => setActiveTab('browse')}
          className="mt-4 px-6 py-2 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-lg font-medium hover:shadow-lg transition-all duration-300"
        >
          Browse Hotels
        </button>
      </div>
    </div>
  );

  const BookingModal = () => {
    if (!selectedHotel) return null;
    
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
        <div className="bg-slate-900 rounded-3xl p-8 max-w-md w-full border border-white/10 shadow-2xl max-h-[90vh] overflow-y-auto">
          {bookingSuccess ? (
            <div className="text-center py-8">
              <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Check className="w-10 h-10 text-green-400" />
              </div>
              <h3 className="text-2xl font-bold mb-2">Booking Confirmed!</h3>
              <p className="text-gray-400">Your reservation at {selectedHotel.name} is confirmed.</p>
            </div>
          ) : (
            <>
              <div className="flex justify-between items-start mb-6">
                <h3 className="text-2xl font-bold">Confirm Booking</h3>
                <button onClick={() => setSelectedHotel(null)} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>
              
              <div className="space-y-4 mb-6">
                <div className="flex items-center gap-4 p-4 bg-white/5 rounded-xl">
                  <img src={selectedHotel.image} alt={selectedHotel.name} className="w-24 h-24 rounded-lg object-cover" />
                  <div className="flex-1">
                    <h4 className="font-bold text-lg">{selectedHotel.name}</h4>
                    <p className="text-gray-400 text-sm flex items-center gap-1">
                      <MapPin className="w-4 h-4" /> {selectedHotel.location}
                    </p>
                    <div className="flex items-center gap-2 mt-2">
                      <Star className="w-4 h-4 text-yellow-400 fill-yellow-400" />
                      <span className="font-bold">{selectedHotel.rating}</span>
                    </div>
                  </div>
                </div>

                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-sm text-gray-400 mb-2">Available Room Types</p>
                  <div className="flex flex-wrap gap-2">
                    {selectedHotel.roomTypes.map((type, idx) => (
                      <span key={idx} className="px-3 py-1 bg-cyan-500/20 text-cyan-400 rounded-full text-sm">
                        {type}
                      </span>
                    ))}
                  </div>
                </div>

                <div className="p-4 bg-white/5 rounded-xl flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Users className="w-5 h-5 text-cyan-400" />
                    <span className="text-sm text-gray-400">Maximum Capacity</span>
                  </div>
                  <span className="font-bold">{selectedHotel.maxGuests} Guests</span>
                </div>

                <div className="space-y-2 text-sm">
                  <div className="flex justify-between py-2 border-b border-white/10">
                    <span className="text-gray-400">Check-in</span>
                    <span>{checkIn ? formatDate(checkIn) : 'Not selected'}</span>
                  </div>
                  <div className="flex justify-between py-2 border-b border-white/10">
                    <span className="text-gray-400">Check-out</span>
                    <span>{checkOut ? formatDate(checkOut) : 'Not selected'}</span>
                  </div>
                  <div className="flex justify-between py-2 border-b border-white/10">
                    <span className="text-gray-400">Guests</span>
                    <span>{selectedGuests}</span>
                  </div>
                  <div className="flex justify-between py-2">
                    <span className="text-gray-400">Price per night</span>
                    <span className="font-bold text-cyan-400">${selectedHotel.price}</span>
                  </div>
                  <div className="flex justify-between pt-2 border-t border-white/10">
                    <span className="text-gray-400">Total</span>
                    <span className="text-2xl font-bold text-cyan-400">
                      ${selectedHotel.price * Math.max(1, Math.ceil(selectedGuests / 2))}
                    </span>
                  </div>
                </div>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={() => setSelectedHotel(null)}
                  className="flex-1 py-3 bg-white/10 rounded-xl font-medium hover:bg-white/20 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={confirmBooking}
                  className="flex-1 py-3 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-xl font-medium hover:shadow-lg transition-all duration-300"
                >
                  Confirm Booking
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white flex">
      <Sidebar />
      <main className="flex-1 p-8 overflow-y-auto relative">
        {activeTab === 'browse' && (
          <BrowseHotels 
            searchQuery={searchQuery}
            onSearchChange={handleSearchChange}
            checkIn={checkIn}
            onCheckInChange={handleCheckInChange}
            checkOut={checkOut}
            onCheckOutChange={handleCheckOutChange}
            selectedGuests={selectedGuests}
            onGuestSelect={handleGuestSelect}
            showGuestDropdown={showGuestDropdown}
            onToggleGuestDropdown={toggleGuestDropdown}
            filteredHotels={filteredHotels}
            onBookNow={handleBookNow}
            guestOptions={guestOptions}
            hoveredHotel={hoveredHotel}
            setHoveredHotel={setHoveredHotel}
            canBook={canBook}
          />
        )}
        {activeTab === 'bookings' && <MyBookings />}
        {activeTab === 'favorites' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">Favorites</h2>
            <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-8 text-center border border-white/10">
              <Heart className="w-16 h-16 text-gray-600 mx-auto mb-4" />
              <p className="text-gray-400">No favorites yet. Start browsing!</p>
            </div>
          </div>
        )}
        {activeTab === 'profile' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">Profile</h2>
            <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-6 max-w-md border border-white/10">
              <div className="flex items-center gap-4 mb-6">
                <div className="w-20 h-20 rounded-full bg-gradient-to-r from-cyan-500 to-purple-500 flex items-center justify-center text-2xl font-bold">
                  {user?.name?.charAt(0) || 'U'}
                </div>
                <div>
                  <h3 className="text-xl font-bold">{user?.name || 'User'}</h3>
                  <p className="text-gray-400">{user?.email || 'user@example.com'}</p>
                </div>
              </div>
              <div className="space-y-4">
                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-sm text-gray-400 mb-1">Member Since</p>
                  <p className="font-medium">April 2026</p>
                </div>
                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-sm text-gray-400 mb-1">Total Bookings</p>
                  <p className="font-medium">0</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
      {selectedHotel && <BookingModal />}
    </div>
  );
};

const BrowseHotels = React.memo(({ 
  searchQuery, 
  onSearchChange, 
  checkIn, 
  onCheckInChange, 
  checkOut, 
  onCheckOutChange, 
  selectedGuests, 
  onGuestSelect,
  showGuestDropdown,
  onToggleGuestDropdown,
  filteredHotels, 
  onBookNow,
  guestOptions,
  hoveredHotel,
  setHoveredHotel,
  canBook
}) => {
  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-4 border border-white/10">
        <div className="grid md:grid-cols-5 gap-4">
          <div className="md:col-span-2 relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 pointer-events-none" />
            <input
              type="text"
              placeholder="Search hotels or destinations..."
              value={searchQuery}
              onChange={onSearchChange}
              className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl focus:border-cyan-500/50 focus:outline-none text-white"
              autoComplete="off"
              spellCheck="false"
            />
          </div>

          <CustomDatePicker 
            label="Check In"
            value={checkIn}
            onChange={onCheckInChange}
            min={today}
            icon={Calendar}
          />

          <CustomDatePicker 
            label="Check Out"
            value={checkOut}
            onChange={onCheckOutChange}
            min={checkIn || today}
            icon={Calendar}
          />

          {/* Guests Dropdown */}
          <div className="relative">
            <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1 ml-1">Guests</label>
            <div className="relative">
              <Users className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-cyan-400 pointer-events-none" />
              <button
                type="button"
                onClick={onToggleGuestDropdown}
                className="w-full pl-12 pr-10 py-3 bg-slate-900/50 border border-white/10 rounded-xl focus:border-cyan-500/50 focus:outline-none text-white text-left flex items-center justify-between hover:bg-slate-800/50 transition-colors"
              >
                <span>{selectedGuests} Guests</span>
                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${showGuestDropdown ? 'rotate-180' : ''}`} />
              </button>
              
              {showGuestDropdown && (
                <div className="absolute top-full left-0 right-0 mt-2 bg-slate-900 border border-white/10 rounded-xl overflow-hidden shadow-xl max-h-60 overflow-y-auto z-50">
                  {guestOptions.map(num => (
                    <button
                      key={num}
                      type="button"
                      onClick={() => onGuestSelect(num)}
                      className={`w-full px-4 py-3 text-left hover:bg-white/10 transition-colors flex items-center justify-between ${
                        selectedGuests === num ? 'bg-cyan-500/20 text-cyan-400' : 'text-white'
                      }`}
                    >
                      <span>{num} Guests</span>
                      {selectedGuests === num && <Check className="w-4 h-4" />}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Warning if dates not selected */}
      {!canBook && (
        <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-xl p-3 flex items-center gap-2 text-yellow-400 text-sm">
          <Calendar className="w-4 h-4" />
          <span>Please select check-in and check-out dates to book a hotel</span>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div className="text-gray-400">
          Showing <span className="text-white font-bold">{filteredHotels.length}</span> properties
          <span className="text-cyan-400 text-sm ml-2">(for {selectedGuests} guests)</span>
        </div>
        <button className="flex items-center gap-2 px-4 py-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-lg hover:bg-white/10 transition-colors">
          <Filter className="w-4 h-4" /> Filters
        </button>
      </div>

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredHotels.map(hotel => (
          <HotelCard 
            key={hotel.id} 
            hotel={hotel} 
            onBookNow={onBookNow}
            isHovered={hoveredHotel === hotel.id}
            onHover={() => setHoveredHotel(hotel.id)}
            onLeave={() => setHoveredHotel(null)}
            canBook={canBook}
          />
        ))}
      </div>
    </div>
  );
});

const HotelCard = React.memo(({ hotel, onBookNow, isHovered, onHover, onLeave, canBook }) => {
  return (
    <div 
      className="group bg-slate-900/50 rounded-2xl overflow-hidden border border-white/10 hover:border-cyan-500/50 transition-all duration-500 hover:shadow-xl hover:shadow-cyan-500/10 relative"
      onMouseEnter={onHover}
      onMouseLeave={onLeave}
    >
      <div className="relative h-48 overflow-hidden">
        <img src={hotel.image} alt={hotel.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
        <div className="absolute top-4 right-4 bg-white/10 backdrop-blur-md px-2 py-1 rounded-lg flex items-center gap-1">
          <Star className="w-4 h-4 text-yellow-400 fill-yellow-400" />
          <span className="font-bold text-sm">{hotel.rating}</span>
        </div>
        
        {isHovered && (
          <div className="absolute inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center transition-all duration-300">
            <div className="text-center p-4">
              <Users className="w-8 h-8 text-cyan-400 mx-auto mb-2" />
              <p className="text-lg font-bold mb-1">{hotel.maxGuests} Persons</p>
              <p className="text-sm text-gray-300">Maximum capacity per room</p>
              <div className="mt-3 flex flex-wrap justify-center gap-1">
                {hotel.roomTypes.slice(0, 2).map((type, idx) => (
                  <span key={idx} className="px-2 py-1 bg-white/20 rounded text-xs">
                    {type}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
      
      <div className="p-5">
        <div className="flex justify-between items-start mb-2">
          <div>
            <h3 className="font-bold text-lg group-hover:text-cyan-400 transition-colors">{hotel.name}</h3>
            <div className="flex items-center gap-1 text-gray-400 text-sm">
              <MapPin className="w-4 h-4" /> {hotel.location}
            </div>
          </div>
          <div className="flex items-center gap-1 text-xs text-gray-400 bg-white/5 px-2 py-1 rounded-lg">
            <Users className="w-3 h-3" />
            <span>Max {hotel.maxGuests}</span>
          </div>
        </div>
        <p className="text-gray-400 text-sm mb-4 line-clamp-2">{hotel.description}</p>
        <div className="flex flex-wrap gap-2 mb-4">
          {hotel.amenities.map((amenity, idx) => (
            <span key={idx} className="px-2 py-1 bg-white/5 rounded-md text-xs text-gray-300 border border-white/10">
              {amenity}
            </span>
          ))}
        </div>
        <div className="flex justify-between items-center pt-4 border-t border-white/10">
          <div>
            <span className="text-2xl font-bold text-cyan-400">${hotel.price}</span>
            <span className="text-gray-500 text-sm">/night</span>
          </div>
          
          <button 
            onClick={() => onBookNow(hotel)}
            disabled={!canBook}
            className={`
              px-4 py-2 rounded-lg font-medium transition-all duration-300
              ${canBook 
                ? 'bg-gradient-to-r from-cyan-500 to-purple-500 hover:shadow-lg hover:shadow-cyan-500/25 text-white' 
                : 'bg-gray-700 text-gray-500 cursor-not-allowed'
              }
            `}
          >
            {canBook ? 'Book Now' : 'Select Dates'}
          </button>
        </div>
      </div>
    </div>
  );
});

export default Dashboard;
